from fastapi import APIRouter, Depends, HTTPExceptionfrom fastapi.responses import FileResponsefrom sqlalchemy.orm import Sessionfrom database import get_dbfrom models import Project, Item, Templatefrom PIL import Image, ImageDraw, ImageFontimport osimport uuidrouter = APIRouter()OUTPUT_DIR = "outputs"os.makedirs(OUTPUT_DIR, exist_ok=True)def wrap_text(text: str, font: ImageFont.FreeTypeFont, max_width: int) -> list[str]:    """Split text into lines that fit within max_width."""    words = text.split()    lines = []    current = ""    for word in words:        test = f"{current} {word}".strip()        if font.getlength(test) <= max_width:            current = test        else:            if current:                lines.append(current)            current = word    if current:        lines.append(current)    return linesdef render_cell(item: Item, layout: dict) -> Image.Image:    """Render a single item cell using the template layout spec."""    cell_w = layout["cell"]["width"]    cell_h = layout["cell"]["height"]    cell = Image.new("RGB", (cell_w, cell_h), (255, 255, 255))    draw = ImageDraw.Draw(cell)    # --- load fonts ---    # fall back to default if custom fonts not found    try:            font_price = ImageFont.truetype("fonts/BebasNeue-Regular.ttf", layout["cell"]["price_font_size"])            font_en = ImageFont.truetype("fonts/NotoSansSC-SemiBold.ttf", layout["cell"]["text_font_size"])            font_zh = ImageFont.truetype("fonts/NotoSansSC-Bold.ttf", layout["cell"]["text_font_size"])            font_notes = ImageFont.truetype("fonts/NotoSansSC-SemiBold.ttf", layout["cell"]["notes_font_size"])    except Exception as e:        print(f"Font loading error: {e}")        font_price = ImageFont.load_default()        font_en = ImageFont.load_default()        font_zh = ImageFont.load_default()        font_notes = ImageFont.load_default()    # --- layer 1: product image ---    img_spec = layout["cell"]["image"]    img_x = img_spec["x"] + item.image_offset_x    img_y = img_spec["y"] + item.image_offset_y    img_w = img_spec["width"]    img_h = img_spec["height"]                if item.image and item.image.url:        filepath = item.image.url.lstrip("/")        if os.path.exists(filepath):            product_img = Image.open(filepath).convert("RGB")            scale = item.image_scale or 1.0            scaled_w = int(img_w * scale)            scaled_h = int(img_h * scale)            product_img = product_img.resize((scaled_w, scaled_h), Image.LANCZOS)            # center the scaled image in the image zone            paste_x = img_x + (img_w - scaled_w) // 2 + item.image_offset_x            paste_y = img_y + (img_h - scaled_h) // 2 + item.image_offset_y            cell.paste(product_img, (paste_x, paste_y))    # --- layer 2: price badge ---    if item.price_amount:        badge = layout["cell"]["price_badge"]        bx, by, br = badge["x"], badge["y"], badge["radius"]        draw.ellipse(            [(bx - br, by - br), (bx + br, by + br)],            fill=badge["color"]        )        # assemble price text        price_text = ""        if item.price_prefix:            price_text += f"{item.price_prefix}\n"        price_text += f"${item.price_amount}"        if item.price_unit:            price_text += f"\n{item.price_unit}"        draw.text(            (bx, by),            price_text,            font=font_price,            fill=badge["text_color"],            anchor="mm",            align="center"        )    # --- layer 3: chinese description ---    if item.description_zh:        zh_spec = layout["cell"]["desc_zh"]        zh_lines = wrap_text(item.description_zh, font_zh, zh_spec["max_width"])        y = zh_spec["y"]        for line in zh_lines:            draw.text((zh_spec["x"], y), line, font=font_zh, fill=zh_spec["color"])            y += layout["cell"]["text_font_size"] + 2    # --- layer 4: english description ---    if item.description_en:        en_spec = layout["cell"]["desc_en"]        en_lines = wrap_text(item.description_en, font_en, en_spec["max_width"])        y = en_spec["y"]        for line in en_lines:            draw.text((en_spec["x"], y), line, font=font_en, fill=en_spec["color"])            y += layout["cell"]["text_font_size"] + 2    # --- layer 5: notes ---    if item.notes:        notes_spec = layout["cell"]["notes"]        draw.text(            (notes_spec["x"], notes_spec["y"]),            item.notes,            font=font_notes,            fill=notes_spec["color"]        )    return celldef assemble_page(cells: list[Image.Image], layout: dict, page_num: int) -> Image.Image:    """Arrange rendered cells into a full page."""    page_w = layout["page"]["width"]    page_h = layout["page"]["height"]    page = Image.new("RGB", (page_w, page_h), (255, 255, 255))    cols = layout["columns"]    margin = layout["page"]["margin"]    gap = layout["page"]["gap"]    cell_w = layout["cell"]["width"]    cell_h = layout["cell"]["height"]    for i, cell_img in enumerate(cells):        col = i % cols        row = i // cols        x = margin + col * (cell_w + gap)        y = margin + row * (cell_h + gap)        page.paste(cell_img, (x, y))    return page@router.post("/{project_id}")def export_project(project_id: str, db: Session = Depends(get_db)):    project = db.query(Project).filter(Project.id == project_id).first()    if not project:        raise HTTPException(status_code=404, detail="Project not found")    template = db.query(Template).filter(Template.id == project.template_id).first()    if not template:        raise HTTPException(status_code=400, detail="Project has no template assigned")    layout = template.layout_spec    items = db.query(Item).filter(        Item.project_id == project_id    ).order_by(Item.position).all()    if not items:        raise HTTPException(status_code=400, detail="Project has no items")    cells_per_page = template.cells_per_page    pages = []    # chunk items into pages    for page_num in range(0, len(items), cells_per_page):        page_items = items[page_num:page_num + cells_per_page]        rendered_cells = [render_cell(item, layout) for item in page_items]        # pad last page with blank cells if needed        while len(rendered_cells) < cells_per_page:            blank = Image.new("RGB", (layout["cell"]["width"], layout["cell"]["height"]), (255, 255, 255))            rendered_cells.append(blank)        page = assemble_page(rendered_cells, layout, page_num)        pages.append(page)    # save all pages as separate images    output_files = []    for i, page in enumerate(pages):        filename = f"{project_id}_page_{i+1}.jpg"        filepath = os.path.join(OUTPUT_DIR, filename)        page.save(filepath, "JPEG", quality=95)        output_files.append(filepath)    # update project status    project.status = "exported"    db.commit()    return {"ok": True, "pages": len(pages), "files": output_files}@router.post("/{project_id}/render_all")def render_all_cells(project_id: str, db: Session = Depends(get_db)):    project = db.query(Project).filter(Project.id == project_id).first()    if not project:        raise HTTPException(status_code=404, detail="Project not found")    template = db.query(Template).filter(Template.id == project.template_id).first()    if not template:        raise HTTPException(status_code=400, detail="Project has no template assigned")    layout = template.layout_spec    items = db.query(Item).filter(Item.project_id == project_id).all()    if not items:        raise HTTPException(status_code=400, detail="Project has no items")    os.makedirs(OUTPUT_DIR, exist_ok=True)    rendered = 0    for item in items:        # only render if stale (no render url or data changed)        if item.cell_render_url is None:            cell_img = render_cell(item, layout)            filename = f"{project_id}_cell_{item.id}.jpg"            filepath = os.path.join(OUTPUT_DIR, filename)            cell_img.save(filepath, "JPEG", quality=95)            item.cell_render_url = f"/outputs/{filename}"            rendered += 1    db.commit()    return {"ok": True, "rendered": rendered, "total": len(items)}@router.get("/{project_id}/page/{page_num}")def get_page(project_id: str, page_num: int):    filepath = os.path.join(OUTPUT_DIR, f"{project_id}_page_{page_num}.jpg")    if not os.path.exists(filepath):        raise HTTPException(status_code=404, detail="Page not found, export first")    return FileResponse(filepath, media_type="image/jpeg")